// ─── UTILS ────────────────────────────────────────────────────────────────────
const today = new Date();
today.setHours(0, 0, 0, 0);
const fmtDate = (d) =>
  d
    ? new Date(d).toLocaleDateString('fr-FR', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
      })
    : '—';
const diffDays = (d) => {
  if (!d) return null;
  const t = new Date(d);
  t.setHours(0, 0, 0, 0);
  return Math.ceil((t - today) / 86400000);
};
const urgScore = (c) => {
  const d = diffDays(c.deadline);
  if (d === null) return 9999;
  if (d < 0) return 9998;
  return d;
};
