// ─── BADGE & PILLS ────────────────────────────────────────────────────────────
function Badge({ statut, t }) {
  const s = STATUTS[statut] || STATUTS['En cours'];
  return (
    <span
      style={{
        background: s.bg,
        color: s.color,
        border: `1px solid ${s.border}`,
        borderRadius: 20,
        padding: '2px 10px',
        fontSize: 11,
        fontWeight: 700,
        whiteSpace: 'nowrap',
      }}
    >
      {t.statLabels[statut] || statut}
    </span>
  );
}
function DeadlinePill({ deadline, t }) {
  if (!deadline)
    return (
      <span style={{ color: '#9CA3AF', fontSize: 11 }}>{t.noDeadline}</span>
    );
  const d = diffDays(deadline);
  let color = '#059669',
    bg = '#ECFDF5',
    border = '#A7F3D0';
  if (d < 0) {
    color = '#9CA3AF';
    bg = '#F9FAFB';
    border = '#E5E7EB';
  } else if (d <= 3) {
    color = '#DC2626';
    bg = '#FEF2F2';
    border = '#FECACA';
  } else if (d <= 7) {
    color = '#D97706';
    bg = '#FFFBEB';
    border = '#FDE68A';
  } else if (d <= 14) {
    color = '#2563EB';
    bg = '#EFF6FF';
    border = '#BFDBFE';
  }
  const label = d < 0 ? t.past : d === 0 ? t.todayLabel : `${t.dayPfx}${d}`;
  return (
    <span
      style={{
        background: bg,
        color,
        border: `1px solid ${border}`,
        borderRadius: 20,
        padding: '2px 10px',
        fontSize: 11,
        fontWeight: 700,
      }}
    >
      {fmtDate(deadline)} ({label})
    </span>
  );
}

// ─── AVATAR ───────────────────────────────────────────────────────────────────
function Avatar({ nom, prenom, photo, size = 40 }) {
  const ini =
    [prenom, nom]
      .filter(Boolean)
      .map((s) => s[0].toUpperCase())
      .join('')
      .slice(0, 2) || '?';
  const cols = [
    '#2563EB',
    '#059669',
    '#D97706',
    '#7C3AED',
    '#DC2626',
    '#0891B2',
    '#65A30D',
    '#C2410C',
  ];
  const ci = (nom || '').charCodeAt(0) % cols.length;
  if (photo)
    return (
      <img
        src={photo}
        alt={ini}
        style={{
          width: size,
          height: size,
          borderRadius: '50%',
          objectFit: 'cover',
          flexShrink: 0,
        }}
      />
    );
  return (
    <div
      style={{
        width: size,
        height: size,
        borderRadius: '50%',
        background: cols[ci],
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        flexShrink: 0,
        color: '#fff',
        fontWeight: 800,
        fontSize: size * 0.36,
      }}
    >
      {ini}
    </div>
  );
}

