// ─── GANTT ────────────────────────────────────────────────────────────────────
function GanttChart({ candidatures, t }) {
  const actives = sortByUrg(
    candidatures.filter(
      (c) =>
        c.statut !== 'Archive' &&
        c.statut !== 'Refuse' &&
        (c.dateDebut || c.deadline)
    )
  );
  if (!actives.length)
    return (
      <div
        style={{
          textAlign: 'center',
          padding: '60px 0',
          color: '#9CA3AF',
          fontSize: 14,
        }}
      >
        {t.ganttEmpty}
      </div>
    );
  const allD = actives
    .flatMap((c) => [c.dateDebut, c.deadline].filter(Boolean))
    .map((d) => new Date(d));
  const minD = new Date(Math.min(...allD));
  minD.setDate(minD.getDate() - 3);
  const maxD = new Date(Math.max(...allD));
  maxD.setDate(maxD.getDate() + 10);
  const totMs = maxD - minD;
  const toX = (d) =>
    Math.max(0, Math.min(100, ((new Date(d) - minD) / totMs) * 100));
  const todayX = toX(today);
  const ticks = [];
  const cur = new Date(minD);
  cur.setDate(cur.getDate() + ((7 - cur.getDay()) % 7));
  while (cur <= maxD) {
    ticks.push({
      x: toX(cur),
      label: cur.toLocaleDateString('fr-FR', {
        day: '2-digit',
        month: '2-digit',
      }),
    });
    cur.setDate(cur.getDate() + 7);
  }
  const ROW = 44,
    HDR = 30,
    LW = 130,
    svgH = HDR + actives.length * ROW + 8;
  return (
    <div style={{ overflowX: 'auto' }}>
      <svg
        width="100%"
        viewBox={`0 0 900 ${svgH}`}
        style={{ fontFamily: 'inherit', minWidth: 600, display: 'block' }}
      >
        {actives.map((_, i) => (
          <rect
            key={i}
            x={0}
            y={HDR + i * ROW}
            width={900}
            height={ROW}
            fill={i % 2 === 0 ? '#F9FAFB' : '#FFF'}
          />
        ))}
        {ticks.map((tk, i) => {
          const px = LW + (tk.x / 100) * (900 - LW);
          return (
            <g key={i}>
              <line
                x1={px}
                y1={HDR}
                x2={px}
                y2={svgH}
                stroke="#E5E7EB"
                strokeWidth={1}
              />
              <text
                x={px}
                y={18}
                textAnchor="middle"
                fontSize={9}
                fill="#9CA3AF"
              >
                {tk.label}
              </text>
            </g>
          );
        })}
        {(() => {
          const px = LW + (todayX / 100) * (900 - LW);
          return (
            <g>
              <line
                x1={px}
                y1={0}
                x2={px}
                y2={svgH}
                stroke="#DC2626"
                strokeWidth={1.5}
                strokeDasharray="4 3"
                opacity={0.6}
              />
              <text
                x={px}
                y={10}
                textAnchor="middle"
                fontSize={8}
                fill="#DC2626"
                fontWeight="bold"
              >
                {t.ganttToday}
              </text>
            </g>
          );
        })()}
        {actives.map((c, i) => {
          const s = STATUTS[c.statut] || STATUTS['En cours'],
            y = HDR + i * ROW;
          const xS = c.dateDebut
            ? LW + (toX(c.dateDebut) / 100) * (900 - LW)
            : LW;
          const xE = c.deadline
            ? LW + (toX(c.deadline) / 100) * (900 - LW)
            : xS + 60;
          const bW = Math.max(xE - xS, 4);
          const dlX = c.deadline
            ? LW + (toX(c.deadline) / 100) * (900 - LW)
            : null;
          return (
            <g key={c.id}>
              <text
                x={LW - 8}
                y={y + ROW / 2 + 1}
                textAnchor="end"
                fontSize={11}
                fill="#374151"
                fontWeight={600}
                dominantBaseline="middle"
              >
                {c.nom.length > 16 ? c.nom.slice(0, 15) + '…' : c.nom}
              </text>
              <rect
                x={xS}
                y={y + 12}
                width={bW}
                height={20}
                fill={s.color + '25'}
                stroke={s.color}
                strokeWidth={1.5}
                rx={4}
              />
              <text
                x={xS + bW / 2}
                y={y + 25}
                textAnchor="middle"
                fontSize={9}
                fill={s.color}
                fontWeight={700}
                dominantBaseline="middle"
              >
                {c.poste
                  ? c.poste.length > 22
                    ? c.poste.slice(0, 21) + '…'
                    : c.poste
                  : c.nom}
              </text>
              {dlX !== null && (
                <polygon
                  points={`${dlX},${y + 6} ${dlX + 6},${y + 14} ${dlX},${
                    y + 22
                  } ${dlX - 6},${y + 14}`}
                  fill="#DC2626"
                  opacity={0.85}
                />
              )}
            </g>
          );
        })}
      </svg>
      <div
        style={{ display: 'flex', gap: 20, marginTop: 10, flexWrap: 'wrap' }}
      >
        {t.ganttLegend.map((l, i) =>
          i < 2 ? (
            <span
              key={i}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 6,
                fontSize: 11,
                color: '#6B7280',
              }}
            >
              <span
                style={{
                  width: 14,
                  height: 10,
                  background: '#2563EB30',
                  border: `1.5px solid #2563EB`,
                  borderRadius: 2,
                  display: 'inline-block',
                }}
              />
              {l}
            </span>
          ) : (
            <span key={i} style={{ fontSize: 11, color: '#DC2626' }}>
              {l}
            </span>
          )
        )}
      </div>
    </div>
  );
}

