// ─── CONTACT CARD ─────────────────────────────────────────────────────────────
function ContactCard({ c, onEdit, onDelete, theme, t }) {
  const [open, setOpen] = useState(false);
  const TH = THEMES[theme];
  const cv = t.cv;
  const rappel = diffDays(c.prochainRappel);
  const urgent = rappel !== null && rappel >= 0 && rappel <= 3;
  const proche = rappel !== null && rappel >= 0 && rappel <= 7;
  const last =
    c.echanges && c.echanges.length > 0
      ? [...c.echanges].sort((a, b) => b.date.localeCompare(a.date))[0]
      : null;
  return (
    <div
      style={{
        border: `1px solid ${
          urgent ? '#FECACA' : TH.sb.replace('1px solid ', '')
        }`,
        borderLeft: `4px solid ${
          urgent ? '#DC2626' : proche ? '#D97706' : '#2563EB'
        }`,
        borderRadius: TH.cr,
        background: TH.cardBg,
        boxShadow: open ? '0 4px 16px #0001' : 'none',
        transition: 'box-shadow 0.15s',
      }}
    >
      <div
        style={{
          padding: '14px 18px',
          cursor: 'pointer',
          display: 'flex',
          alignItems: 'center',
          gap: 14,
        }}
        onClick={() => setOpen((o) => !o)}
      >
        <Avatar nom={c.nom} prenom={c.prenom} photo={c.photo} size={42} />
        <div style={{ flex: 1, minWidth: 0 }}>
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 8,
              flexWrap: 'wrap',
            }}
          >
            <span style={{ fontSize: 15, fontWeight: 800, color: '#111827' }}>
              {[c.prenom, c.nom].filter(Boolean).join(' ')}
            </span>
            {urgent && (
              <span
                style={{
                  fontSize: 10,
                  background: '#FEF2F2',
                  color: '#DC2626',
                  border: '1px solid #FECACA',
                  borderRadius: 10,
                  padding: '1px 8px',
                  fontWeight: 700,
                }}
              >
                {cv.urgBadge}
              </span>
            )}
            {!urgent && proche && (
              <span
                style={{
                  fontSize: 10,
                  background: '#FFFBEB',
                  color: '#D97706',
                  border: '1px solid #FDE68A',
                  borderRadius: 10,
                  padding: '1px 8px',
                  fontWeight: 700,
                }}
              >
                {cv.nearBadge}
              </span>
            )}
          </div>
          <div style={{ fontSize: 12, color: '#6B7280', marginTop: 2 }}>
            {[c.poste, c.entreprise].filter(Boolean).join(' · ')}
          </div>
          <div
            style={{
              display: 'flex',
              gap: 10,
              marginTop: 5,
              flexWrap: 'wrap',
              alignItems: 'center',
            }}
          >
            {c.prochainRappel && (
              <span
                style={{
                  fontSize: 11,
                  background: urgent
                    ? '#FEF2F2'
                    : proche
                    ? '#FFFBEB'
                    : '#EFF6FF',
                  color: urgent ? '#DC2626' : proche ? '#D97706' : '#2563EB',
                  border: `1px solid ${
                    urgent ? '#FECACA' : proche ? '#FDE68A' : '#BFDBFE'
                  }`,
                  borderRadius: 20,
                  padding: '1px 9px',
                  fontWeight: 700,
                }}
              >
                {t.reminderLabel} : {fmtDate(c.prochainRappel)}
                {rappel !== null && rappel >= 0
                  ? ` (${t.dayPfx}${rappel})`
                  : ''}
              </span>
            )}
            {last && (
              <span style={{ fontSize: 11, color: '#9CA3AF' }}>
                {cv.lastExchange} : {fmtDate(last.date)} · {last.type}
              </span>
            )}
          </div>
        </div>
        <div style={{ display: 'flex', gap: 6, flexShrink: 0 }}>
          <button
            onClick={(e) => {
              e.stopPropagation();
              onEdit(c);
            }}
            style={{
              background: '#EFF6FF',
              border: 'none',
              borderRadius: Math.max(TH.cr - 2, 2),
              padding: '5px 11px',
              cursor: 'pointer',
              fontSize: 12,
              color: '#2563EB',
              fontFamily: 'inherit',
            }}
          >
            {t.edit}
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation();
              if (window.confirm(cv.confirmDelete + ' ?')) onDelete(c.id);
            }}
            style={{
              background: '#FEF2F2',
              border: 'none',
              borderRadius: Math.max(TH.cr - 2, 2),
              padding: '5px 11px',
              cursor: 'pointer',
              fontSize: 12,
              color: '#DC2626',
              fontFamily: 'inherit',
            }}
          >
            {t.del}
          </button>
          <span style={{ color: '#9CA3AF', fontSize: 14, marginLeft: 4 }}>
            {open ? '▲' : '▼'}
          </span>
        </div>
      </div>
      {open && (
        <div style={{ borderTop: '1px solid #F3F4F6', padding: '16px 18px' }}>
          <div
            style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}
          >
            <div>
              <div
                style={{
                  fontSize: 10,
                  fontWeight: 700,
                  color: '#6B7280',
                  textTransform: 'uppercase',
                  letterSpacing: '0.06em',
                  marginBottom: 8,
                }}
              >
                {cv.sCoords}
              </div>
              <div
                style={{
                  background: '#F9FAFB',
                  borderRadius: 6,
                  padding: '10px 12px',
                  fontSize: 12,
                  display: 'flex',
                  flexDirection: 'column',
                  gap: 5,
                }}
              >
                {c.email && (
                  <div>
                    <a href={`mailto:${c.email}`} style={{ color: '#2563EB' }}>
                      {c.email}
                    </a>
                  </div>
                )}
                {c.tel && <div style={{ color: '#374151' }}>{c.tel}</div>}
                {c.linkedin && (
                  <div>
                    <a
                      href={c.linkedin}
                      target="_blank"
                      rel="noreferrer"
                      style={{ color: '#2563EB' }}
                    >
                      {cv.linkedinLabel}
                    </a>
                  </div>
                )}
                {!c.email && !c.tel && !c.linkedin && (
                  <div style={{ color: '#9CA3AF' }}>{cv.noCoords}</div>
                )}
              </div>
            </div>
            {c.notes && (
              <div>
                <div
                  style={{
                    fontSize: 10,
                    fontWeight: 700,
                    color: '#6B7280',
                    textTransform: 'uppercase',
                    letterSpacing: '0.06em',
                    marginBottom: 8,
                  }}
                >
                  {cv.sNotes}
                </div>
                <div
                  style={{
                    background: '#FFFBEB',
                    borderRadius: 6,
                    padding: '10px 12px',
                    fontSize: 12,
                    color: '#92400E',
                    border: '1px solid #FDE68A',
                  }}
                >
                  {c.notes}
                </div>
              </div>
            )}
            {c.echanges && c.echanges.length > 0 && (
              <div style={{ gridColumn: '1 / -1' }}>
                <div
                  style={{
                    fontSize: 10,
                    fontWeight: 700,
                    color: '#6B7280',
                    textTransform: 'uppercase',
                    letterSpacing: '0.06em',
                    marginBottom: 8,
                  }}
                >
                  {cv.sHistory}
                </div>
                <div
                  style={{ borderLeft: '2px solid #E5E7EB', paddingLeft: 14 }}
                >
                  {[...c.echanges]
                    .sort((a, b) => b.date.localeCompare(a.date))
                    .map((e, i) => (
                      <div
                        key={i}
                        style={{ marginBottom: 8, position: 'relative' }}
                      >
                        <div
                          style={{
                            position: 'absolute',
                            left: -18,
                            top: 5,
                            width: 8,
                            height: 8,
                            background: '#2563EB',
                            borderRadius: '50%',
                          }}
                        />
                        <div
                          style={{
                            display: 'flex',
                            gap: 8,
                            alignItems: 'center',
                          }}
                        >
                          <span
                            style={{
                              fontSize: 10,
                              color: '#9CA3AF',
                              fontFamily: 'monospace',
                            }}
                          >
                            {fmtDate(e.date)}
                          </span>
                          <span
                            style={{
                              fontSize: 10,
                              background: '#EFF6FF',
                              color: '#2563EB',
                              border: '1px solid #BFDBFE',
                              borderRadius: 10,
                              padding: '0 7px',
                              fontWeight: 700,
                            }}
                          >
                            {e.type}
                          </span>
                        </div>
                        <div
                          style={{
                            fontSize: 12,
                            color: '#374151',
                            marginTop: 2,
                          }}
                        >
                          {e.texte}
                        </div>
                      </div>
                    ))}
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

// ─── CONTACTS VIEW ────────────────────────────────────────────────────────────
function VueContacts({ contacts, setContacts, theme, t }) {
  const [modal, setModal] = useState(null);
  const [search, setSearch] = useState('');
  const cv = t.cv;
  const TH = THEMES[theme];
  const save = (form) => {
    setContacts((d) =>
      d.find((c) => c.id === form.id)
        ? d.map((c) => (c.id === form.id ? form : c))
        : [...d, form]
    );
    setModal(null);
  };
  const del = (id) => setContacts((d) => d.filter((c) => c.id !== id));
  const filtered = useMemo(() => {
    let list = [...contacts].sort((a, b) => {
      const ra = diffDays(a.prochainRappel),
        rb = diffDays(b.prochainRappel);
      if (ra === null && rb === null) return 0;
      if (ra === null) return 1;
      if (rb === null) return -1;
      if (ra < 0 && rb < 0) return ra - rb;
      if (ra < 0) return 1;
      if (rb < 0) return -1;
      return ra - rb;
    });
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter((c) =>
        [c.prenom, c.nom, c.entreprise, c.poste]
          .filter(Boolean)
          .some((s) => s.toLowerCase().includes(q))
      );
    }
    return list;
  }, [contacts, search]);
  return (
    <div>
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: 20,
          flexWrap: 'wrap',
          gap: 10,
        }}
      >
        <div>
          <h2
            style={{
              margin: 0,
              fontSize: 15,
              fontWeight: 800,
              color: '#111827',
            }}
          >
            {cv.title}
          </h2>
          <p style={{ margin: '4px 0 0', fontSize: 12, color: '#9CA3AF' }}>
            {cv.sub(contacts.length)}
          </p>
        </div>
        <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
          <input
            placeholder={t.search}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{ ...S.inp, width: 200, margin: 0 }}
          />
          <button
            onClick={() => setModal('new')}
            style={{
              background: '#1D4ED8',
              color: '#fff',
              border: 'none',
              borderRadius: TH.cr,
              padding: '8px 18px',
              fontWeight: 700,
              fontSize: 13,
              cursor: 'pointer',
              fontFamily: 'inherit',
            }}
          >
            {cv.newBtn}
          </button>
        </div>
      </div>
      {contacts.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '80px 20px' }}>
          <div
            style={{
              width: 64,
              height: 64,
              background: '#EFF6FF',
              borderRadius: '50%',
              margin: '0 auto 20px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            <span style={{ fontSize: 24, color: '#2563EB', fontWeight: 300 }}>
              +
            </span>
          </div>
          <h3
            style={{
              margin: '0 0 8px',
              fontSize: 18,
              fontWeight: 800,
              color: '#111827',
            }}
          >
            {cv.emptyTitle}
          </h3>
          <p
            style={{
              margin: '0 0 24px',
              fontSize: 14,
              color: '#6B7280',
              maxWidth: 340,
              marginLeft: 'auto',
              marginRight: 'auto',
            }}
          >
            {cv.emptyText}
          </p>
          <button
            onClick={() => setModal('new')}
            style={{
              background: '#1D4ED8',
              color: '#fff',
              border: 'none',
              borderRadius: 10,
              padding: '10px 24px',
              fontWeight: 700,
              fontSize: 14,
              cursor: 'pointer',
              fontFamily: 'inherit',
            }}
          >
            {cv.emptyBtn}
          </button>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
          {filtered.length === 0 && (
            <p
              style={{
                color: '#9CA3AF',
                textAlign: 'center',
                padding: '40px 0',
              }}
            >
              {cv.noMatch}
            </p>
          )}
          {filtered.map((c) => (
            <ContactCard
              key={c.id}
              c={c}
              onEdit={setModal}
              onDelete={del}
              theme={theme}
              t={t}
            />
          ))}
        </div>
      )}
      {modal && (
        <ContactModal
          contact={modal === 'new' ? null : modal}
          onSave={save}
          onClose={() => setModal(null)}
          t={t}
        />
      )}
    </div>
  );
}

// ─── FICHE CARD ───────────────────────────────────────────────────────────────
function FicheCard({ c, onEdit, onDelete, onToggleTache, theme, t }) {
  const [open, setOpen] = useState(false);
  const s = STATUTS[c.statut] || STATUTS['En cours'];
  const tr = c.taches.filter((x) => !x.fait).length;
  const dl = diffDays(c.deadline);
  const isUrg = dl !== null && dl >= 0 && dl <= 3;
  const TH = THEMES[theme];
  const em = t.em;
  const PRIO = {
    haute: { color: '#DC2626', label: em.pHaute },
    normale: { color: '#D97706', label: em.pNorm },
    basse: { color: '#6B7280', label: em.pBasse },
  };
  return (
    <div
      style={{
        border: `1px solid ${
          isUrg ? '#FECACA' : TH.sb.replace('1px solid ', '')
        }`,
        borderLeft: `4px solid ${s.color}`,
        borderRadius: TH.cr,
        background: TH.cardBg,
        boxShadow: open ? '0 4px 16px #0001' : 'none',
        transition: 'box-shadow 0.15s',
      }}
    >
      <div
        style={{
          padding: '14px 18px',
          cursor: 'pointer',
          display: 'flex',
          alignItems: 'flex-start',
          gap: 12,
        }}
        onClick={() => setOpen((o) => !o)}
      >
        <div style={{ flex: 1, minWidth: 0 }}>
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 8,
              flexWrap: 'wrap',
            }}
          >
            <span style={{ fontSize: 15, fontWeight: 800, color: '#111827' }}>
              {c.nom}
            </span>
            <Badge statut={c.statut} t={t} />
            {isUrg && (
              <span
                style={{
                  fontSize: 10,
                  background: '#FEF2F2',
                  color: '#DC2626',
                  border: '1px solid #FECACA',
                  borderRadius: 10,
                  padding: '1px 8px',
                  fontWeight: 700,
                }}
              >
                {t.urgent}
              </span>
            )}
          </div>
          <div style={{ fontSize: 12, color: '#6B7280', marginTop: 3 }}>
            {[
              c.poste,
              c.ref && c.ref !== '—' ? `Ref. ${c.ref}` : null,
              c.secteur,
            ]
              .filter(Boolean)
              .join(' · ')}
          </div>
          <div
            style={{
              display: 'flex',
              gap: 8,
              marginTop: 6,
              flexWrap: 'wrap',
              alignItems: 'center',
            }}
          >
            <DeadlinePill deadline={c.deadline} t={t} />
            {tr > 0 && (
              <span
                style={{
                  fontSize: 11,
                  background: '#FFFBEB',
                  color: '#92400E',
                  border: '1px solid #FDE68A',
                  borderRadius: 10,
                  padding: '1px 8px',
                  fontWeight: 700,
                }}
              >
                {t.pendTask(tr)}
              </span>
            )}
          </div>
        </div>
        <div
          style={{
            display: 'flex',
            gap: 6,
            alignItems: 'center',
            flexShrink: 0,
          }}
        >
          <button
            onClick={(e) => {
              e.stopPropagation();
              onEdit(c);
            }}
            style={{
              background: '#EFF6FF',
              border: 'none',
              borderRadius: Math.max(TH.cr - 2, 2),
              padding: '5px 11px',
              cursor: 'pointer',
              fontSize: 12,
              color: '#2563EB',
              fontFamily: 'inherit',
            }}
          >
            {t.edit}
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation();
              if (window.confirm(t.confirm(c.nom))) onDelete(c.id);
            }}
            style={{
              background: '#FEF2F2',
              border: 'none',
              borderRadius: Math.max(TH.cr - 2, 2),
              padding: '5px 11px',
              cursor: 'pointer',
              fontSize: 12,
              color: '#DC2626',
              fontFamily: 'inherit',
            }}
          >
            {t.del}
          </button>
          <span style={{ color: '#9CA3AF', fontSize: 14, marginLeft: 4 }}>
            {open ? '▲' : '▼'}
          </span>
        </div>
      </div>
      {open && (
        <div style={{ borderTop: '1px solid #F3F4F6', padding: '16px 18px' }}>
          <div
            style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}
          >
            {c.contacts.length > 0 && (
              <div>
                <div
                  style={{
                    fontSize: 10,
                    fontWeight: 700,
                    color: '#6B7280',
                    textTransform: 'uppercase',
                    letterSpacing: '0.06em',
                    marginBottom: 8,
                  }}
                >
                  {em.sContacts}
                </div>
                {c.contacts.map((ct, i) => (
                  <div
                    key={i}
                    style={{
                      fontSize: 12,
                      marginBottom: 8,
                      background: '#F9FAFB',
                      borderRadius: 6,
                      padding: '8px 10px',
                    }}
                  >
                    <div style={{ fontWeight: 700, color: '#374151' }}>
                      {ct.nom}
                    </div>
                    {ct.poste && (
                      <div style={{ color: '#6B7280' }}>{ct.poste}</div>
                    )}
                    {ct.email && (
                      <div>
                        <a
                          href={`mailto:${ct.email}`}
                          style={{ color: '#2563EB' }}
                        >
                          {ct.email}
                        </a>
                      </div>
                    )}
                    {ct.tel && <div style={{ color: '#6B7280' }}>{ct.tel}</div>}
                  </div>
                ))}
              </div>
            )}
            {c.taches.length > 0 && (
              <div>
                <div
                  style={{
                    fontSize: 10,
                    fontWeight: 700,
                    color: '#6B7280',
                    textTransform: 'uppercase',
                    letterSpacing: '0.06em',
                    marginBottom: 8,
                  }}
                >
                  {em.sTasks}
                </div>
                {c.taches.map((x, i) => {
                  const p = PRIO[x.priorite] || PRIO.normale;
                  return (
                    <div
                      key={i}
                      style={{
                        display: 'flex',
                        alignItems: 'flex-start',
                        gap: 8,
                        marginBottom: 6,
                        fontSize: 12,
                      }}
                    >
                      <input
                        type="checkbox"
                        checked={x.fait}
                        onChange={() => onToggleTache(c.id, i)}
                        style={{
                          marginTop: 1,
                          cursor: 'pointer',
                          flexShrink: 0,
                        }}
                      />
                      <span
                        style={{
                          textDecoration: x.fait ? 'line-through' : 'none',
                          color: x.fait ? '#9CA3AF' : p.color,
                          fontWeight:
                            !x.fait && x.priorite === 'haute' ? 700 : 400,
                        }}
                      >
                        {!x.fait && (
                          <span
                            style={{
                              fontSize: 10,
                              color: p.color,
                              marginRight: 4,
                            }}
                          >
                            [{p.label}]
                          </span>
                        )}
                        {x.texte}
                      </span>
                    </div>
                  );
                })}
              </div>
            )}
            {c.actions.length > 0 && (
              <div style={{ gridColumn: '1 / -1' }}>
                <div
                  style={{
                    fontSize: 10,
                    fontWeight: 700,
                    color: '#6B7280',
                    textTransform: 'uppercase',
                    letterSpacing: '0.06em',
                    marginBottom: 8,
                  }}
                >
                  {em.sHistory}
                </div>
                <div
                  style={{ borderLeft: '2px solid #E5E7EB', paddingLeft: 14 }}
                >
                  {[...c.actions]
                    .sort((a, b) => b.date.localeCompare(a.date))
                    .map((a, i) => (
                      <div
                        key={i}
                        style={{ marginBottom: 8, position: 'relative' }}
                      >
                        <div
                          style={{
                            position: 'absolute',
                            left: -18,
                            top: 6,
                            width: 8,
                            height: 8,
                            background: '#2563EB',
                            borderRadius: '50%',
                          }}
                        />
                        <div
                          style={{
                            fontSize: 10,
                            color: '#9CA3AF',
                            fontFamily: 'monospace',
                          }}
                        >
                          {fmtDate(a.date)}
                        </div>
                        <div style={{ fontSize: 12, color: '#374151' }}>
                          {a.texte}
                        </div>
                      </div>
                    ))}
                </div>
              </div>
            )}
            {c.notes && (
              <div
                style={{
                  gridColumn: '1 / -1',
                  background: '#FFFBEB',
                  borderRadius: 6,
                  padding: '8px 12px',
                  fontSize: 12,
                  color: '#92400E',
                  border: '1px solid #FDE68A',
                }}
              >
                {c.notes}
              </div>
            )}
            {c.liens.length > 0 && (
              <div style={{ gridColumn: '1 / -1' }}>
                <div
                  style={{
                    fontSize: 10,
                    fontWeight: 700,
                    color: '#6B7280',
                    textTransform: 'uppercase',
                    letterSpacing: '0.06em',
                    marginBottom: 6,
                  }}
                >
                  {em.sLinks}
                </div>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                  {c.liens.map((l, i) => (
                    <a
                      key={i}
                      href={l.url}
                      target="_blank"
                      rel="noreferrer"
                      style={{
                        fontSize: 11,
                        color: '#2563EB',
                        background: '#EFF6FF',
                        border: '1px solid #BFDBFE',
                        borderRadius: 6,
                        padding: '3px 10px',
                        textDecoration: 'none',
                      }}
                    >
                      {l.label || l.url}
                    </a>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

